SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS `ref_hewan`;
CREATE TABLE `ref_hewan` (
`id_hewan` TEXT,
  `nama_hewan` TEXT,
  `kategori` TEXT
);


DROP TABLE IF EXISTS `ref_wilayah`;
CREATE TABLE `ref_wilayah` (
`id_wilayah` INT,
  `provinsi` TEXT
);


DROP TABLE IF EXISTS `tr_mutasi`;
CREATE TABLE `tr_mutasi` (
`id_mutasi` TEXT,
  `tgl_mutasi` TEXT,
  `id_asal` INT,
  `id_tujuan` INT,
  `id_hewan` TEXT,
  `jumlah_ekor` DOUBLE
);


DROP TABLE IF EXISTS `tr_laporan_sakit`;
CREATE TABLE `tr_laporan_sakit` (
`id_laporan` TEXT,
  `tgl_lapor` TEXT,
  `id_wilayah` INT,
  `id_hewan` TEXT,
  `jumlah_gejala` DOUBLE,
  `jumlah_mati` DOUBLE
);


DROP TABLE IF EXISTS `tr_hasil_lab`;
CREATE TABLE `tr_hasil_lab` (
`id_uji` TEXT,
  `id_laporan` TEXT,
  `tgl_uji` TEXT,
  `penyakit` TEXT,
  `hasil_uji` TEXT
);


DROP TABLE IF EXISTS `tr_rph`;
CREATE TABLE `tr_rph` (
`id_potong` TEXT,
  `tgl_potong` TEXT,
  `id_wilayah` INT,
  `id_hewan` TEXT,
  `berat_karkas` DOUBLE
);


SET FOREIGN_KEY_CHECKS = 1;
